const input = $input.first().json;
const action = input.action;

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const API_BASE = 'https://api.cloud.vexa.ai';

// Fetch API key
const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.vexa-meetings&cred_key=eq.vexa_api_key&select=cred_value',
  headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
});

if (!creds || creds.length === 0 || !creds[0].cred_value) {
  return [{ json: { error: 'Vexa API key not configured. Use add_credential to set it up.' } }];
}

const apiKey = creds[0].cred_value;
const apiHeaders = { 'X-API-Key': apiKey, 'Content-Type': 'application/json' };

// Parse meeting URL to extract platform and meeting ID
function parseMeetingUrl(url) {
  if (!url) return null;
  url = url.trim();

  // Google Meet: https://meet.google.com/abc-defg-hij
  const gmeetMatch = url.match(/meet\.google\.com\/([a-z]{3}-[a-z]{4}-[a-z]{3})/i);
  if (gmeetMatch) return { platform: 'google_meet', native_meeting_id: gmeetMatch[1] };

  // Microsoft Teams: https://teams.live.com/meet/1234567890123?p=XYZ
  const teamsMatch = url.match(/teams\.(?:live|microsoft)\.com\/(?:meet|l\/meetup-join)\/([^?&#]+)/);
  if (teamsMatch) {
    const meetingId = teamsMatch[1];
    const passcodeMatch = url.match(/[?&]p=([^&]+)/);
    return { platform: 'teams', native_meeting_id: meetingId, passcode: passcodeMatch ? passcodeMatch[1] : undefined };
  }

  // Zoom: https://us05web.zoom.us/j/12345678901?pwd=...
  const zoomMatch = url.match(/zoom\.us\/j\/(\d+)/);
  if (zoomMatch) {
    const pwdMatch = url.match(/[?&]pwd=([^&]+)/);
    return { platform: 'zoom', native_meeting_id: zoomMatch[1], passcode: pwdMatch ? pwdMatch[1] : undefined };
  }

  return null;
}

// ── ACTION: deploy_meeting_bot ──
if (action === 'deploy_meeting_bot') {
  const meetingUrl = input.meeting_url;
  if (!meetingUrl) {
    return [{ json: { error: 'Parameter "meeting_url" is required. Provide a Google Meet, Teams, or Zoom URL.' } }];
  }

  const parsed = parseMeetingUrl(meetingUrl);
  if (!parsed) {
    return [{ json: { error: 'Could not parse meeting URL. Supported: Google Meet (meet.google.com/xxx-xxxx-xxx), Microsoft Teams (teams.live.com/meet/...), Zoom (zoom.us/j/...)' } }];
  }

  const body = {
    platform: parsed.platform,
    native_meeting_id: parsed.native_meeting_id
  };
  if (parsed.passcode) body.passcode = parsed.passcode;
  if (input.language) body.language = input.language;
  if (input.bot_name) body.bot_name = input.bot_name;
  if (input.recording !== undefined) body.recording_enabled = input.recording === true || input.recording === 'true';

  try {
    const data = await helpers.httpRequest({
      method: 'POST',
      url: API_BASE + '/bots',
      headers: apiHeaders,
      body: JSON.stringify(body)
    });

    let result = 'Bot deployed successfully!\n';
    result += '  Platform: ' + parsed.platform + '\n';
    result += '  Meeting ID: ' + parsed.native_meeting_id + '\n';
    result += '  Status: ' + (data.status || 'requested') + '\n';
    if (data.constructed_meeting_url) result += '  URL: ' + data.constructed_meeting_url + '\n';
    result += '\nThe bot will join the meeting shortly and start transcribing.';
    result += '\nUse get_transcript with platform="' + parsed.platform + '" and meeting_id="' + parsed.native_meeting_id + '" to fetch the transcript later.';

    return [{ json: { result } }];
  } catch (err) {
    const msg = err.message || '';
    if (msg.includes('401') || msg.includes('403')) {
      return [{ json: { error: 'Authentication failed. Check your Vexa API key.' } }];
    }
    return [{ json: { error: 'Failed to deploy bot: ' + msg } }];
  }

// ── ACTION: get_transcript ──
} else if (action === 'get_transcript') {
  let platform = input.platform;
  let meetingId = input.meeting_id;

  // Also accept meeting_url for convenience
  if (input.meeting_url && (!platform || !meetingId)) {
    const parsed = parseMeetingUrl(input.meeting_url);
    if (parsed) {
      platform = parsed.platform;
      meetingId = parsed.native_meeting_id;
    }
  }

  if (!platform || !meetingId) {
    return [{ json: { error: 'Parameters "platform" (google_meet/teams/zoom) and "meeting_id" are required.' } }];
  }

  try {
    const data = await helpers.httpRequest({
      method: 'GET',
      url: API_BASE + '/transcripts/' + encodeURIComponent(platform) + '/' + encodeURIComponent(meetingId),
      headers: { 'X-API-Key': apiKey }
    });

    if (!data.segments || data.segments.length === 0) {
      let result = 'No transcript segments available yet.';
      if (data.status) result += ' Meeting status: ' + data.status;
      return [{ json: { result } }];
    }

    let result = 'Transcript for ' + platform + ' meeting ' + meetingId + '\n';
    result += 'Status: ' + (data.status || 'unknown') + '\n';
    if (data.start_time) result += 'Started: ' + data.start_time + '\n';
    if (data.end_time) result += 'Ended: ' + data.end_time + '\n';
    result += '\n--- Transcript ---\n\n';

    for (const seg of data.segments) {
      const speaker = seg.speaker || 'Unknown';
      const text = seg.text || '';
      result += speaker + ': ' + text + '\n';
    }

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to fetch transcript: ' + err.message } }];
  }

// ── ACTION: share_transcript ──
} else if (action === 'share_transcript') {
  let platform = input.platform;
  let meetingId = input.meeting_id;

  if (input.meeting_url && (!platform || !meetingId)) {
    const parsed = parseMeetingUrl(input.meeting_url);
    if (parsed) {
      platform = parsed.platform;
      meetingId = parsed.native_meeting_id;
    }
  }

  if (!platform || !meetingId) {
    return [{ json: { error: 'Parameters "platform" and "meeting_id" are required.' } }];
  }

  try {
    const data = await helpers.httpRequest({
      method: 'POST',
      url: API_BASE + '/transcripts/' + encodeURIComponent(platform) + '/' + encodeURIComponent(meetingId) + '/share',
      headers: apiHeaders
    });

    let result = 'Shareable transcript link created:\n';
    result += '  URL: ' + data.url + '\n';
    result += '  Expires: ' + data.expires_at + '\n';
    result += '  Valid for: ' + Math.round(data.expires_in_seconds / 60) + ' minutes';

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to create share link: ' + err.message } }];
  }

// ── ACTION: list_bots ──
} else if (action === 'list_bots') {
  try {
    const data = await helpers.httpRequest({
      method: 'GET',
      url: API_BASE + '/bots/status',
      headers: { 'X-API-Key': apiKey }
    });

    const bots = data.running_bots || [];
    if (bots.length === 0) {
      return [{ json: { result: 'No bots currently running.' } }];
    }

    let result = 'Running bots (' + bots.length + '):\n\n';
    for (const bot of bots) {
      result += '- ' + (bot.platform || 'unknown') + ' / ' + (bot.native_meeting_id || bot.meeting_id_from_name || '?') + '\n';
      result += '  Status: ' + (bot.normalized_status || bot.status || 'unknown') + '\n';
      if (bot.created_at) result += '  Started: ' + bot.created_at + '\n';
      result += '\n';
    }

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list bots: ' + err.message } }];
  }

// ── ACTION: stop_bot ──
} else if (action === 'stop_bot') {
  let platform = input.platform;
  let meetingId = input.meeting_id;

  if (input.meeting_url && (!platform || !meetingId)) {
    const parsed = parseMeetingUrl(input.meeting_url);
    if (parsed) {
      platform = parsed.platform;
      meetingId = parsed.native_meeting_id;
    }
  }

  if (!platform || !meetingId) {
    return [{ json: { error: 'Parameters "platform" and "meeting_id" are required.' } }];
  }

  try {
    await helpers.httpRequest({
      method: 'DELETE',
      url: API_BASE + '/bots/' + encodeURIComponent(platform) + '/' + encodeURIComponent(meetingId),
      headers: { 'X-API-Key': apiKey }
    });

    return [{ json: { result: 'Bot stop request accepted. The bot will leave the meeting shortly.' } }];
  } catch (err) {
    return [{ json: { error: 'Failed to stop bot: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Available: deploy_meeting_bot, get_transcript, share_transcript, list_bots, stop_bot' } }];
}
